/* --- DOCUMENTS & INVOICING MODULE (WITH FULL PIPELINE WORKFLOW & SECURITY) --- */

let currentDocTab = 'All';
let editingDocId = null;

function isUserAdmin() {
    return typeof Enterprise !== 'undefined' && Enterprise.security.isAdmin(false);
}

function draftEmailToBuyer() {
    const buyer = document.getElementById('doc-buyer')?.value || '';
    const no = document.getElementById('doc-no')?.value || '';
    const type = document.getElementById('doc-type')?.value || '';
    if (!buyer) {
        alert("Please enter a buyer email address in the Buyer field first.");
        return;
    }
    const emailMatch = buyer.match(/([a-zA-Z0-9._-]+@[a-zA-Z0-9._-]+\.[a-zA-Z0-9_-]+)/gi);
    const email = emailMatch ? emailMatch[0] : '';
    const subject = encodeURIComponent(`${type} - ${no} attached from JFT Agro`);
    window.open(`mailto:${email}?subject=${subject}`);
}

function printShippingLabels() {
    if(typeof Enterprise !== 'undefined') Enterprise.notify("Preparing Shipping Labels...", "info");
    else alert("Preparing Shipping Labels...");
}

function syncToGoogleDrive(documentNo, documentType, buyerName) {
    if (!db.meta || !db.meta.gdriveSync) return;
    const year = new Date().getFullYear();
    const safeBuyerName = (buyerName || 'Unknown').replace(/[\/\\]/g, '-');
    const safeDocNo = (documentNo || 'Draft').replace(/[\/\\]/g, '-');
    const safeFilename = `${documentType.replace(/ /g, '_')}_${safeDocNo}.pdf`;

    // NOTE: Full GDrive PDF push requires the Google Drive API OAuth flow (not yet implemented).
    // This currently logs the intended path for audit trail only. 
    if (typeof Enterprise !== 'undefined') {
        const folderPath = `JFT Drive / ${year} / Buyers / ${safeBuyerName}`;
        Enterprise.logAction(`[GDrive Queued] ${safeFilename} → ${folderPath}`);
        // Only notify if gdriveSync is explicitly enabled and API is connected
        if (db.meta.gdriveApiConnected) {
            Enterprise.notify(`☁️ Archiving to Google Drive: ${folderPath}`, "info");
        }
    }
}

function resetSecurityBlindMode() {
    document.querySelectorAll('.rate-col').forEach(el => {
        el.style.display = 'table-cell';
        el.classList.remove('hidden');
    });
    
    const financialBlocks = [
        'data-advance', 'data-freight', 'data-insurance', 
        'doc-sub-total', 'doc-cif-total', 'doc-fob-total', 'doc-total'
    ];
    financialBlocks.forEach(id => {
        const el = document.getElementById(id);
        if (el) {
            const parentDiv = el.closest('div');
            if (parentDiv) parentDiv.style.display = '';
        }
    });

    const currEl = document.getElementById('doc-currency');
    if (currEl) {
        currEl.disabled = false;
        currEl.style.background = '';
    }
}

function enforceSecurityBlindMode() {
    if (isUserAdmin()) return;
    if(typeof Enterprise !== 'undefined') Enterprise.notify("Security Blind Mode Active: Financials hidden.", "info");

    document.querySelectorAll('.rate-col').forEach(el => el.style.display = 'none');
    const financialBlocks = [
        'data-advance', 'data-freight', 'data-insurance', 
        'doc-sub-total', 'doc-cif-total', 'doc-fob-total', 'doc-total'
    ];
    financialBlocks.forEach(id => {
        const el = document.getElementById(id);
        if (el) {
            const parentDiv = el.closest('div');
            if (parentDiv) parentDiv.style.display = 'none';
        }
    });

    const currEl = document.getElementById('doc-currency');
    if (currEl) {
        currEl.disabled = true;
        currEl.style.background = 'var(--border)';
    }
}

function autoGenerateDocNo(type) {
    const fyLabel = typeof getFYLabel === 'function' ? getFYLabel() : new Date().getFullYear();
    const prefix = `${type.split(' ')[0].toUpperCase()}/${fyLabel}/`;
    
    if (!db.docs || db.docs.length === 0) return `${prefix}001`;
    
    // Filter docs that match the current Fiscal Year prefix
    const currentFYDocs = db.docs.filter(d => d.no && d.no.startsWith(prefix));
    
    if (currentFYDocs.length === 0) return `${prefix}001`;

    // Extract the numeric portion and find the max
    const indices = currentFYDocs.map(d => {
        const parts = d.no.split('/');
        const lastPart = parseInt(parts[parts.length - 1]);
        return isNaN(lastPart) ? 0 : lastPart;
    });

    const nextIndex = Math.max(...indices) + 1;
    return `${prefix}${nextIndex.toString().padStart(3, '0')}`;
}

function openAddressBook() {
    const modal = document.getElementById('address-book-modal');
    const list = document.getElementById('ab-list');
    if (!modal || !list) return;

    const allBuyersRaw = db.docs.map(d => (d.buyer || '').trim()).filter(b => b !== '');
    const uniqueBuyers = [...new Set(allBuyersRaw)].sort();
    window.addressBookData = uniqueBuyers; 

    modal.classList.remove('hidden');
    modal.style.display = 'flex';
    document.getElementById('ab-search').value = '';
    renderAddressBookList(uniqueBuyers);
}

function closeAddressBook() {
    const modal = document.getElementById('address-book-modal');
    if (modal) {
        modal.classList.add('hidden');
        modal.style.display = 'none';
    }
}

function filterAddressBook() {
    const query = document.getElementById('ab-search').value.toLowerCase();
    const filtered = window.addressBookData.filter(b => b.toLowerCase().includes(query));
    renderAddressBookList(filtered);
}

function renderAddressBookList(buyersArr) {
    const list = document.getElementById('ab-list');
    if (buyersArr.length === 0) {
        list.innerHTML = `<div style="padding: 20px; text-align: center; color: var(--text-muted);">No matching buyers found in history.</div>`;
        return;
    }

    list.innerHTML = buyersArr.map(b => {
        const shortName = escapeHTML(b.split('\n')[0]);
        const safeData = encodeURIComponent(b);
        return `
        <div class="ab-item" style="padding: 15px; border-bottom: 1px solid var(--border); cursor: pointer; transition: background 0.2s;" onmouseover="this.style.background='white'" onmouseout="this.style.background='transparent'" onclick="selectAddressBookEntry('${safeData}')">
            <strong style="color: var(--primary); display: block; margin-bottom: 5px;">${shortName}</strong>
            <div style="font-size: 0.8rem; color: var(--text-muted); white-space: pre-wrap; line-height: 1.3;">${escapeHTML(b)}</div>
        </div>`;
    }).join('');
}

window.selectAddressBookEntry = function(encodedBuyer) {
    const buyerStr = decodeURIComponent(encodedBuyer);
    document.getElementById('doc-buyer').value = buyerStr;
    closeAddressBook();
    if(typeof Enterprise !== 'undefined') Enterprise.notify("✅ Buyer Address Auto-Filled!", "success");
};

function initDocFilters() {
    Enterprise.initFYSelector('filter-fy');
}

window.clearDocFilters = function() {
    const fySelect = document.getElementById('filter-fy');
    if(fySelect && fySelect.options[1]) fySelect.value = fySelect.options[1].value; 
    document.getElementById('filter-date-from').value = '';
    document.getElementById('filter-date-to').value = '';
    document.getElementById('filter-limit').value = '25';
    document.getElementById('doc-search').value = '';
    renderDocList();
};

function renderDocTabsUI() {
    const container = document.querySelector('#documents .doc-tab-container');
    if (!container) return;
    
    db.uiConfig = { docTypes: ['Sales Contract', 'Proforma Invoice', 'Customs Invoice', 'Commercial Invoice', 'Packing List', 'Phyto Draft', 'COO Draft', 'OBL Draft'] };
    
    const existingSearch = document.getElementById('doc-search')?.value || '';
    let html = `<button class="sub-tab-btn ${currentDocTab === 'All' ? 'active' : ''}" onclick="switchDocTab('All')">All</button>`;
    
    db.uiConfig.docTypes.forEach(type => {
        let shortType = type.replace(' Invoice', '').replace(' Draft', '').replace(' Contract', '');
        if (type === 'Sales Contract') shortType = 'Contract';
        const isActive = currentDocTab === type ? 'active' : '';
        const safeTypeStr = escapeHTML(type).replace(/&#039;/g, "\\'");
        html += `<button class="sub-tab-btn ${isActive}" onclick="switchDocTab('${safeTypeStr}')">${escapeHTML(shortType)}</button>`;
    });

    html += `<input type="text" id="doc-search" placeholder="Search No or Buyer..." oninput="renderDocList()" style="margin-left: auto; width: 200px; margin-top: 0; margin-bottom: 0; min-width: 150px;" value="${escapeHTML(existingSearch)}">`;

    html += `
    <div style="display:flex; gap:10px; align-items:center; margin-left:10px;">
        <select id="dynamic-create-doc-select" style="margin:0; padding:6px 12px; border-radius:4px; font-weight:bold; border:1px solid var(--primary);">
            ${db.uiConfig.docTypes.map(t => `<option value="${escapeHTML(t)}">${escapeHTML(t)}</option>`).join('')}
        </select>
        <button onclick="createNewDoc(document.getElementById('dynamic-create-doc-select').value)">+ Create</button>
    </div>`;

    container.innerHTML = html;
    initDocFilters();
    renderDocList();
}

function switchDocTab(tabName) {
    currentDocTab = tabName;
    renderDocTabsUI(); 
    renderDocList();
}

function toggleDocLock(id) {
    const d = db.docs.find(x => x.id === id);
    if (!d) return;
    
    if (d.isLocked) {
        if (!isUserAdmin()) {
            if(typeof Enterprise !== 'undefined') Enterprise.notify("Security Alert: Only Admins can unlock this document.", "danger");
            else alert("Only Admins can unlock this document.");
            return;
        }
        d.isLocked = false;
        if(typeof Enterprise !== 'undefined') Enterprise.notify(`Document ${d.no} unlocked for editing.`, "success");
    } else {
        d.isLocked = true;
        if(typeof Enterprise !== 'undefined') Enterprise.notify(`Document ${d.no} securely locked.`, "success");
    }
    
    if (typeof saveData === 'function') saveData();
    renderDocList();
}

function renderDocList() {
    const tbody = document.querySelector('#doc-list-table tbody');
    if (!tbody) return;

    const searchQ = (document.getElementById('doc-search')?.value || '').toLowerCase();
    const filterFy = document.getElementById('filter-fy')?.value || '';
    const dateFrom = document.getElementById('filter-date-from')?.value || '';
    const dateTo = document.getElementById('filter-date-to')?.value || '';
    const limitStr = document.getElementById('filter-limit')?.value || '25';
    const limit = parseInt(limitStr, 10);
    
    let filtered = db.docs.filter(d => {
        if (currentDocTab !== 'All' && d.type !== currentDocTab) return false;
        if (searchQ && !d.no.toLowerCase().includes(searchQ) && !d.buyer.toLowerCase().includes(searchQ)) return false;
        
        const dDate = new Date(d.date);
        if (isNaN(dDate.getTime())) return true; 

        if (dateFrom && dDate < new Date(dateFrom)) return false;
        if (dateTo && dDate > new Date(dateTo)) return false;

        return Enterprise.checkFY(d.date, filterFy);
    });

    filtered.sort((a, b) => (new Date(b.date).getTime() || 0) - (new Date(a.date).getTime() || 0));
    
    const paginatedData = filtered.slice(0, limit);
    const isBlind = !isUserAdmin();

    if (paginatedData.length === 0) {
        tbody.innerHTML = `<tr><td colspan="7" style="text-align:center; padding:20px; color:var(--text-muted);">No documents found for the selected filters.</td></tr>`;
        return;
    }

    tbody.innerHTML = paginatedData.map(d => {
        let badge = d.status || 'Draft';
        let badgeClass = badge.replace(/\s+/g, '');

        const displayDate = typeof formatDateIN === 'function' ? formatDateIN(d.date) : d.date;
        
        let valDisplay = '';
        if (isBlind) {
            valDisplay = '<i style="color:var(--border); font-size: 0.8rem;">---</i>';
        } else {
            const dispTotal = d.type === 'Commercial Invoice' || d.type === 'Sales Contract' ? (d.cifTotal || d.subTotal || d.total) : (d.fobTotal || d.subTotal || d.total); 
            valDisplay = `${escapeHTML(d.currency)} ${dispTotal ? parseFloat(dispTotal).toFixed(2) : '0.00'}`;
        }
        
        let lockIcon = '';
        if (d.isLocked) lockIcon = ' <span title="Accounting Locked">🔒</span>';
        if (typeof DocLocker !== 'undefined' && DocLocker.isLockedByOther(d)) lockIcon = ' <span title="Currently being edited">⚠️</span>';

        const safeId = escapeHTML(d.id).replace(/&#039;/g, "\\'");

        let lockActionBtn = '';
        if (d.isLocked) {
            lockActionBtn = `<button class="icon-btn" style="padding: 4px 8px; font-size: 1rem; color: #b45309;" title="Unlock" onclick="toggleDocLock('${safeId}')">🔓</button>`;
        } else {
            lockActionBtn = `<button class="icon-btn" style="padding: 4px 8px; font-size: 1rem; color: #475569;" title="Lock" onclick="toggleDocLock('${safeId}')">🔒</button>`;
        }

        return `<tr>
            <td>${displayDate}</td>
            <td><b>${escapeHTML(d.no)}</b>${lockIcon}</td>
            <td>${escapeHTML(d.type)}</td>
            <td>${escapeHTML(d.buyer.split('\n')[0])}</td>
            <td><span class=\"status-badge status-${badgeClass}\">${escapeHTML(badge)}</span></td>
            <td>${valDisplay}</td>
            <td>
                <div style=\"display:flex; gap:5px; flex-wrap: wrap; align-items:center;\">
                    <button class=\"icon-btn\" style=\"padding: 4px 8px; font-size: 1rem; color: var(--primary);\" title=\"Edit / View\" onclick=\"editDoc('${safeId}')\">👁️</button>
                    <button class=\"icon-btn\" style=\"padding: 4px 8px; font-size: 1rem; color: #0284c7;\" title=\"Clone\" onclick=\"cloneDoc('${safeId}')\">👯</button>
                    ${lockActionBtn}
                    <button class=\"icon-btn danger\" style=\"padding: 4px 8px; font-size: 1rem; background:transparent; color: var(--danger);\" title=\"Delete\" onclick=\"deleteDoc('${safeId}')\">🗑️</button>
                </div>
            </td>
        </tr>`;
    }).join('');
}

