function deleteDoc(id) {
    const d = db.docs.find(x => x.id === id);
    if (d && d.isLocked && !isUserAdmin()) {
        if(typeof Enterprise !== 'undefined') Enterprise.notify("Cannot delete. Document is locked for accounting validation.", "danger");
        else alert("Cannot delete. Document is securely locked.");
        return;
    }
    if(typeof Enterprise !== 'undefined' && !Enterprise.security.canDelete()) return;
    if(!confirm("Are you sure you want to permanently delete this document and its linked workflows?")) return;
    
    db.docs = db.docs.filter(doc => doc.id !== id);
    if (db.expenses) db.expenses = db.expenses.filter(e => e.docId !== id);
    if (db.forex) db.forex = db.forex.filter(f => f.docId !== id);
    
    if(d && typeof Enterprise !== 'undefined') Enterprise.logAction(`Deleted Document: ${d.type} - ${d.no}`);
    if (typeof saveData === 'function') saveData(); 
    renderDocList();
}

function closeEditor() {
    if (editingDocId && typeof DocLocker !== 'undefined') {
        DocLocker.unlock('docs', editingDocId);
    }
    editingDocId = null;
    const editor = document.getElementById('doc-editor');
    if(editor) editor.classList.add('hidden');
    renderDocList();
}

function numberToWords(num) {
    if (isNaN(num)) return '';
    const a = ['','One ','Two ','Three ','Four ', 'Five ','Six ','Seven ','Eight ','Nine ','Ten ','Eleven ','Twelve ','Thirteen ','Fourteen ','Fifteen ','Sixteen ','Seventeen ','Eighteen ','Nineteen '];
    const b = ['', '', 'Twenty','Thirty','Forty','Fifty', 'Sixty','Seventy','Eighty','Ninety'];
    if ((num = num.toString()).length > 9) return 'Overflow';
    const n = ('000000000' + num).substr(-9).match(/^(\d{2})(\d{2})(\d{2})(\d{1})(\d{2})$/);
    if (!n) return ''; var str = '';
    str += (n[1] != 0) ? (a[Number(n[1])] || b[n[1][0]] + ' ' + a[n[1][1]]) + 'Crore ' : '';
    str += (n[2] != 0) ? (a[Number(n[2])] || b[n[2][0]] + ' ' + a[n[2][1]]) + 'Lakh ' : '';
    str += (n[3] != 0) ? (a[Number(n[3])] || b[n[3][0]] + ' ' + a[n[3][1]]) + 'Thousand ' : '';
    str += (n[4] != 0) ? (a[Number(n[4])] || b[n[4][0]] + ' ' + a[n[4][1]]) + 'Hundred ' : '';
    str += (n[5] != 0) ? ((str != '') ? 'and ' : '') + (a[Number(n[5])] || b[n[5][0]] + ' ' + a[n[5][1]]) : '';
    return str.trim();
}

